mapper.select:
SELECT log.year AS year, count(log.year) AS count FROM ( SELECT substring(log.use_time, 1, 4) AS year FROM xeus.mon_cctv_log log LEFT JOIN xeus.mt_usr_desc usr ON usr.user_id = log.usr_id LEFT JOIN xeus.mt_orgz_desc orgz ON usr.org_mgr_no = orgz.org_mgr_no WHERE log.usr_id IS NOT NULL
AND orgz.org_nm = #{orgNm}
) log GROUP BY log.year ORDER BY log.year

SELECT log.month AS month, count(log.month) AS count FROM ( SELECT substring(log.use_time, 5, 2) AS month FROM xeus.mon_cctv_log log LEFT JOIN xeus.mt_usr_desc usr ON usr.user_id = log.usr_id LEFT JOIN xeus.mt_orgz_desc orgz ON usr.org_mgr_no = orgz.org_mgr_no WHERE log.usr_id IS NOT NULL
AND log.use_time LIKE #{year}||'%'
AND orgz.org_nm = #{orgNm}
) log GROUP BY log.month ORDER BY log.month

SELECT log.day AS day, count(log.day) AS count FROM ( SELECT substring(log.use_time, 7, 2) AS day FROM xeus.mon_cctv_log log LEFT JOIN xeus.mt_usr_desc usr ON usr.user_id = log.usr_id LEFT JOIN xeus.mt_orgz_desc orgz ON usr.org_mgr_no = orgz.org_mgr_no WHERE log.usr_id IS NOT NULL
AND log.use_time LIKE #{year}||'%'
AND log.use_time LIKE '____'||#{month}||'%'
AND orgz.org_nm = #{orgNm}
) log GROUP BY log.day ORDER BY log.day
